import{_ as t,o as e,c as i,aQ as o}from"./chunks/framework.cDvftfeu.js";const c=JSON.parse('{"title":"图书馆","description":"如何使用Ham预约图书馆座位。","frontmatter":{"description":"如何使用Ham预约图书馆座位。"},"headers":[],"relativePath":"handbook/library.md","filePath":"handbook/library.md","lastUpdated":1777525243000}'),l={name:"handbook/library.md"};function r(h,a,d,n,u,p){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="图书馆" tabindex="-1">图书馆 <a class="header-anchor" href="#图书馆" aria-label="Permalink to &quot;图书馆&quot;">​</a></h1><p>你可以通过Ham便捷地使用图书馆预约功能</p><h2 id="准备使用" tabindex="-1">准备使用 <a class="header-anchor" href="#准备使用" aria-label="Permalink to &quot;准备使用&quot;">​</a></h2><p>在使用图书馆前，你需要准备：</p><ul><li>信息门户账号</li></ul><h3 id="准备信息门户账号" tabindex="-1">准备信息门户账号 <a class="header-anchor" href="#准备信息门户账号" aria-label="Permalink to &quot;准备信息门户账号&quot;">​</a></h3><p>图书馆座位预约系统通过信息门户（CAS）统一认证登录。你需要在Ham中设置好信息门户账号和密码。如果你忘记了信息门户账号密码，请前往信息门户网站重置。</p><h2 id="看板预约" tabindex="-1">看板预约 <a class="header-anchor" href="#看板预约" aria-label="Permalink to &quot;看板预约&quot;">​</a></h2><p>看板预约，顾名思义你可以看着每个图书馆每个房间每个座位的空余情况，有空位的话直接预约。</p><p>看板预约适用的情况：</p><ul><li>你某一天突然想去图书馆但没有预约</li><li>你不在乎要预约哪个房间、哪个座位</li></ul><p>看板预约位于图书馆功能选项卡的第一个（旧版本为&quot;预约&quot;）。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>看板预约在预约前不会检查该座位的剩余情况。即在你选择座位后，但该座位被其他同学成功预约时，看板预约并不会帮助你选择附近的座位。</p></div><h2 id="快速预约" tabindex="-1">快速预约 <a class="header-anchor" href="#快速预约" aria-label="Permalink to &quot;快速预约&quot;">​</a></h2><p>你可以保存喜爱的座位，然后直接点击预约预约之。</p><p>快速预约使用的情况：</p><ul><li>你经常去图书馆，经常坐在一个固定的位置</li><li>你需要使用自动化预约功能</li><li>你突然想去图书馆，想坐在某个房间中</li></ul><p>在你曾在Ham预约过座位，或选择&quot;首选座位&quot;后，快速预约选项卡将出现在图书馆的主页上。你也可以点击座位、时间临时更改座位与预约时间。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>快速预约尽量满足你&quot;首选座位&quot;选择的需求。在你选择的座位预约失败后，Ham会立刻选择附近的座位预约。</p></div><h2 id="首选座位" tabindex="-1">首选座位 <a class="header-anchor" href="#首选座位" aria-label="Permalink to &quot;首选座位&quot;">​</a></h2><p>快速预约时的默认座位。</p><p>你可以提前选择需要预约的时间、座位、偏好。在你每次进入图书馆页面时，快速预约将自动选择你的设置。</p><p>首选座位设置位于&quot;图书馆设置&quot;中。</p><h2 id="预约状态" tabindex="-1">预约状态 <a class="header-anchor" href="#预约状态" aria-label="Permalink to &quot;预约状态&quot;">​</a></h2><p>当Ham查询到你拥有有效预约时，将会显示在图书馆主页与状态页上。</p><p>你可以在预约状态上更改预约时间、或取消预约。</p><p>如果你预约了较长时间，入馆后需要在中途离开一段时间（超过图书馆允许的限制），你也可以在离开前更改预约时间，让你在回来图书馆时也能坐到先前的座位上。</p><p>Ham获取预约状态后，会自动将该事项添加到系统日历中，并在入馆前10分钟提醒。（iOS）</p><p>预约状态已适配灵动岛与LiveActivity，处于&quot;已预约&quot;状态的预约将会在通知栏中固定，并展示座位号、位置、时间等信息。（iOS）</p><h2 id="历史记录" tabindex="-1">历史记录 <a class="header-anchor" href="#历史记录" aria-label="Permalink to &quot;历史记录&quot;">​</a></h2><p>你可以查看你的图书馆预约记录。</p><h2 id="小组件" tabindex="-1">小组件 <a class="header-anchor" href="#小组件" aria-label="Permalink to &quot;小组件&quot;">​</a></h2><p>你可以将小组件放在桌面上，以提醒你预约的地点、时间，或你临时离开的时间。</p><p>你也可以设置小组件的更新时间，但如果更新时间过短，可能会导致图书馆临时封号（一般15分钟为宜）。</p><h2 id="其它图书馆设置" tabindex="-1">其它图书馆设置 <a class="header-anchor" href="#其它图书馆设置" aria-label="Permalink to &quot;其它图书馆设置&quot;">​</a></h2><h3 id="更新基础数据" tabindex="-1">更新基础数据 <a class="header-anchor" href="#更新基础数据" aria-label="Permalink to &quot;更新基础数据&quot;">​</a></h3><p>一般而言，当你进入预约页面时，Ham会首先使用本地的图书馆房间数据减少网络访问、加快预约速度。在你每次进入“图书馆”，Ham都会尝试更新基础数据。</p><ul><li>从图书馆系统更新</li></ul><p>该选项下会在本机登录图书馆系统获取基本数据。</p><h3 id="重置" tabindex="-1">重置 <a class="header-anchor" href="#重置" aria-label="Permalink to &quot;重置&quot;">​</a></h3><p>当图书馆出现异常情况时，请点击&quot;重置&quot;</p><h3 id="自动化-android" tabindex="-1">自动化（Android） <a class="header-anchor" href="#自动化-android" aria-label="Permalink to &quot;自动化（Android）&quot;">​</a></h3><p>首先在Ham软件中设置好首选座位，自动化设置位于&quot;我的&quot;-&quot;自动化&quot;中。开启后，Ham将会在设定的时间预约&quot;首选座位&quot;。预约时，Ham会根据系统时间判断是否预约明天。</p><h3 id="自动化-ios" tabindex="-1">自动化（iOS） <a class="header-anchor" href="#自动化-ios" aria-label="Permalink to &quot;自动化（iOS）&quot;">​</a></h3><p>首先在Ham软件中设置好首选座位，然后在快捷指令的“自动化”中“创建个人自动化”，选定特定时间，“添加操作”-“App”-“Ham”-“快速预约图书馆”，并关闭运行前询问。开启后，Ham将会在设定的时间预约&quot;首选座位&quot;。预约时，Ham会根据系统时间判断是否预约明天。</p><h3 id="灵动岛-liveactivity" tabindex="-1">灵动岛 / LiveActivity <a class="header-anchor" href="#灵动岛-liveactivity" aria-label="Permalink to &quot;灵动岛 / LiveActivity&quot;">​</a></h3><p>符合状态的预约将在适当时候&quot;上岛&quot;。</p><h2 id="必要的权限" tabindex="-1">必要的权限 <a class="header-anchor" href="#必要的权限" aria-label="Permalink to &quot;必要的权限&quot;">​</a></h2><h3 id="自动化" tabindex="-1">自动化 <a class="header-anchor" href="#自动化" aria-label="Permalink to &quot;自动化&quot;">​</a></h3><ul><li>Android: 自启动</li></ul><h3 id="小组件-1" tabindex="-1">小组件 <a class="header-anchor" href="#小组件-1" aria-label="Permalink to &quot;小组件&quot;">​</a></h3><ul><li>Android: 自启动</li></ul>',52)])])}const q=t(l,[["render",r]]);export{c as __pageData,q as default};
